"/portal/Trabalhador/ConsultaCompleto?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c&tsv=true\">Gestão de Trabalhadores</a></li>\r\n                                    <li><a id=\"\" href=\"/portal/Tsv/InicioCompleto?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c\">Cadastrar</a></li>\r\n                                    <li><a id=\"\" href=\"/portal/AdmissaoPreliminar/AdmissaoPreliminarCompleto?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c&tsv=true\">Admissão Preliminar</a></li>\r\n                                <li role=\"separator\" class=\"divider hidden-md hidden-lg\"></li>\r\n                            </ul>\r\n                        </li>\r\n                        <li class=\"dropdown\">\r\n                            <a id=\"menuDownload\" href=\"javascript:void(0)\" class=\"dropdown-toggle hidden-sm hidden-xs geral\" data-toggle=\"dropdown\" data-hover=\"dropdown\" role=\"button\">Download<span class=\"caret\"></span></a>\r\n\r\n                            <ul class=\"dropdown-menu\" role=\"menu\">\r\n                                \r\n                                <li class=\"dropdown-header hidden-md hidden-lg\">Download</li>\r\n\r\n                                <li><a id=\"\" href=\"/portal/download/Pedido/Solicitacao\">Solicitação</a></li>\r\n                                <li><a id=\"\" href=\"/portal/download/Pedido/Consulta\">Consulta</a></li>\r\n                            </ul>\r\n                        </li>\r\n                    <li class=\"dropdown\">\r\n                        <a id=\"menuFolhaPagamento\" href=\"javascript:void(0)\" class=\"dropdown-toggle hidden-xs hidden-sm\" data-toggle=\"dropdown\" data-hover=\"dropdown\" role=\"button\">Folha de Pagamento<span class=\"caret\"></span></a>\r\n\r\n                        <ul class=\"dropdown-menu\" role=\"menu\">\r\n                            \r\n                            <li class=\"dropdown-header hidden-md hidden-lg\">Folha de Pagamento</li>\r\n\r\n                            <li>\r\n                                <a id=\"menuGestaoFolha\" href=\"/portal/FolhaPagamento/GestaoFolha?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c\">Gestão de Folha</a>\r\n                            </li>\r\n\r\n                            <li class=\"dropdown-submenu\">\r\n                                <a id=\"menuTotalizadores\" href=\"javascript:void(0)\" class=\"dropdown-toggle hidden-sm hidden-xs\">Totalizadores</a>\r\n\r\n                                <ul class=\"dropdown-menu\" role=\"menu\">\r\n                                    \r\n                                    <li class=\"dropdown-header hidden-md hidden-lg\">Totalizadores</li>\r\n\r\n                                    <li class=\"dropdown-submenu\">\r\n                                        <a id=\"menuTotalizadoresEmpregador\" href=\"javascript:void(0)\" class=\"dropdown-toggle hidden-sm hidden-xs\">Empregador</a>\r\n\r\n                                        <ul class=\"dropdown-menu\" role=\"menu\">\r\n                                            <li class=\"dropdown-header hidden-md hidden-lg\">Empregador</li>\r\n\r\n                                            <li><a id=\"menuContribuicaoPrevidenciariaEmpregador\" href=\"/portal/Totalizador/ContribuicoesSociais?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c\">Contribuição Previdenciária</a></li>\r\n                                            <li><a id=\"menuFgtsEmpregador\" href=\"/portal/Totalizador/FGTSPorEmpregador?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c\">FGTS</a></li>\r\n                                            <li><a id=\"menuImpostoRendaEmpregador\" href=\"/portal/Totalizador/ImpostoRenda?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c\">Imposto de Renda</a></li>\r\n\r\n                                            \r\n                                            <li role=\"separator\" class=\"divider hidden-md hidden-lg\"></li>\r\n                                        </ul>\r\n                                    </li>\r\n\r\n                                    <li class=\"dropdown-submenu\">\r\n                                        <a id=\"menuTotalizadoresTrabalhador\" href=\"javascript:void(0)\" class=\"dropdown-toggle hidden-sm hidden-xs\">Trabalhador</a>\r\n\r\n                                        <ul class=\"dropdown-menu\" role=\"menu\">\r\n                                            <li class=\"dropdown-header hidden-md hidden-lg\">Trabalhador</li>\r\n\r\n                                            <li><a id=\"menuContribuicaoSocialTrabalhador\" href=\"/portal/Totalizador/TotalizadorContribuicaoPrevidenciaria?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c\">Contribuição Previdenciária</a></li>\r\n                                            <li><a id=\"menuFgtsTrabalhador\" href=\"/portal/Totalizador/FGTSPorTrabalhador?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c\">FGTS</a></li>\r\n                                            <li><a id=\"menuImpostoRendaTrabalhador\" href=\"/portal/Totalizador/TotalizadorImpostoRenda?id=61f231d3-2b46-4571-9bfb-def8eeba5f6c\">IRRF por trabalhador</a></li>\r\n\r\n                                            \r\n                                            <li role=\"separator\" class=\"divider hidden-md hidden-lg\"></li>\r\n                                        </ul>\r\n                                    </li>\r\n\r\n                                    \r\n                                    <li role=\"separator\" class=\"divider hidden-md hidden-lg\"></li>\r\n                                </ul>\r\n                            </li>\r\n                        </ul>\r\n                    </li>\r\n                    <li class=\"dropdown\">\r\n                        <a id=\"menuAjuda\" href=\"javascript:void(0)\" class=\"dropdown-toggle hidden-xs hidden-sm\" data-toggle=\"dropdown\" data-hover=\"dropdown\">Ajuda<span class=\"caret\"></span></a>\r\n\r\n                        <ul class=\"dropdown-menu\" role=\"menu\">\r\n                            \r\n                            <li class=\"dropdown-header hidden-md hidden-lg\">Ajuda</li>\r\n\r\n                            <li><a id=\"menuTutorial\" target=\"_blank\" onblur=\"$('#loading').fadeOut();\" href=\"https://www.gov.br/esocial/pt-br/empresas/manual-web-geral\">Manual</a></li>\r\n                            <li><a id=\"menuManual\" target=\"_blank\" onblur=\"$('#loading').fadeOut();\" href=\"https://www.gov.br/esocial/pt-br/documentacao-tecnica\">Documentação Técnica</a></li>\r\n                            <li><a id=\"menuPerguntas\" target=\"_blank\" onblur=\"$('#loading').fadeOut();\" href=\"https://www.gov.br/esocial/pt-br/empresas/perguntas-frequentes\">Perguntas Frequentes</a></li>\r\n                        </ul>\r\n                    </li>\r\n    </ul>\r\n    <button class=\"btn btn-link btn-menu-mobile-close hidden-md hidden-lg\">Fechar Menu</button>\r\n\r\n                        </div>\r\n\r\n            </div>\r\n        </div>\r\n\r\n\r\n    <div id=\"page-content\" class=\"container-fluid\">\r\n        <div id=\"conteudo-pagina\">\r\n            ﻿\r\n\r\n\r\n<link href=\"/portal/Content/folha-pagamento?v=3kk1Fm0e2_27r5I1RgpFv3-tyaImsnhtjr5rSr-Dv1A1\" rel=\"stylesheet\"/>\r\n\r\n<link href=\"/portal/Content/slick?v=nGtxpHtyU-D-BAsEkoknTcrCsnPZ8bqBD_4AKHwMpT41\" rel=\"stylesheet\"/>\r\n\r\n\r\n\r\n<div id=\"mensagemGeral\">\r\n\r\n\r\n\r\n\r\n\r\n\r\n</div>\r\n<input id=\"AcessouCodigoAcesso\" name=\"AcessouCodigoAcesso\" type=\"hidden\" value=\"\" /><input id=\"PermitirRepresentanteLegal\" name=\"PermitirRepresentanteLegal\" type=\"hidden\" value=\"\" /><input data-val=\"true\" data-val-required=\"Campo de preenchimento obrigatório.\" id=\"ExibirApoioFinanceiroSul\" name=\"ExibirApoioFinanceiroSul\" type=\"hidden\" value=\"False\" />\r\n\r\n\r\n<div id=\"blocoPaginaInicial\">\r\n    \r\n                <div class=\"col-md-11 orientacoes-iniciais\">\r\n                    <h1 class=\"titulo-pagina\" style=\"margin-top:-10px;\">eSocial – Módulo Geral Pessoa Jur&#237;dica</h1>\r\n\r\n                    <p class=\"text-left\"><span class=\"font-weight-bold\">Orientações gerais:</span></p>\r\n                    <div class=\"col-md-6\">\r\n                        <p class=\"text-justify\">\r\n                            O Módulo Geral Pessoa Jur&#237;dica  é uma ferramenta auxiliar para a inserção de dados no eSocial.\r\n                        </p>\r\n                        <p class=\"text-justify\">\r\n                            Pode ser usado por qualquer usuário e permite que sejam cumpridas as obrigações legais em situações de contingência ou indisponibilidade do seu próprio software.\r\n                        </p>\r\n                        <p class=\"text-justify\">\r\n                            O sistema permitirá também a consulta e edição dos eventos enviados por meio de web service(sistema próprio da empresa). Serão exibidos, além do conteúdo do evento, os números de recibo.\r\n                        </p>\r\n                        <p class=\"text-justify\">\r\n                            O usuário deverá utilizar as ferramentas de pesquisa para selecionar o item a ser consultado.\r\n                        </p>\r\n                    </div>\r\n\r\n                    <div class=\"col-md-6 orientacoes\">\r\n                        <p class=\"text-left\"><span class=\"font-weight-bold\">Menu Empregador</span></p>\r\n                        <ul>\r\n                            <li><span class=\"font-weight-bold\">Dados do Empregador</span> - eventos iniciais</li>\r\n                            <li><span class=\"font-weight-bold\">Tabelas</span> - eventos de tabela(cargos, estabelecimentos, horários, lotações tributárias, etc.).</li>\r\n                        </ul>\r\n\r\n                        <p class=\"text-left\"><span class=\"font-weight-bold\">Menu Empregado</span></p>\r\n                        <ul>\r\n                            <li><span class=\"font-weight-bold\">Gestão de Empregados</span> - dados cadastrais, dados contratuais, movimentações trabalhistas.</li>\r\n                            <li><span class=\"font-weight-bold\">Admitir/Cadastrar</span> </li>\r\n                            <li><span class=\"font-weight-bold\">Admissão preliminar</span> </li>\r\n                        </ul>\r\n\r\n                        <p class=\"text-left\"><span class=\"font-weight-bold\">Menu Trabalhador sem Vínculo</span></p>\r\n                        <ul>\r\n                            <li><span class=\"font-weight-bold\">Gestão de Trabalhadores</span> - dados cadastrais, dados contratuais, movimentações trabalhistas.</li>\r\n                            <li><span class=\"font-weight-bold\">Cadastrar</span> </li>\r\n                        </ul>\r\n                    </div>\r\n                </div>\r\n\r\n    \r\n\r\n\r\n\r\n    <div id=\"dialog-reajustar-salario-trabalhador\" style=\"display: none\">\r\n        <input type=\"hidden\" autofocus=\"autofocus\" />\r\n        <input type=\"hidden\" id=\"idContratoReajusteSalarioTrabalhador\" />\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            Trabalhador: <span id=\"identificacao-trabalhador\" style=\"font-weight: 500;\"></span>\r\n        </div>\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            O salário atual do trabalhador é de <span id=\"valor-salario-atual\" style=\"font-weight: 500;\"></span> por\r\n            <span class=\"frequencia-salario-atual\" style=\"font-weight: 500;\"></span>.\r\n        </div>\r\n        <div class=\"row\" id=\"informacoes-reajuste-salario-trabalhador\">\r\n            <div style=\"float: left; margin-right: 8px;\">O salário novo será de</div>\r\n            <div class=\"form-group\" style=\"float: left; width: 150px; margin-top: -10px;\">\r\n                <input class=\"form-control dinheiro valor-positivo\" data-val=\"true\" data-val-number=\"O campo ValorNovoSalario deve ser um número.\" data-val-required=\"Campo de preenchimento obrigatório.\" id=\"ValorNovoSalario\" maxlength=\"18\" name=\"ValorNovoSalario\" type=\"text\" value=\"0\" />\r\n                <span id=\"validacao_ValorNovoSalario\" class=\"tag-campo-obrigatorio\" style=\"display: none\">Valor informado deve ser maior que ZERO.</span>\r\n            </div>\r\n            <div style=\"float: left; width: auto; margin-left: 8px; margin-right: 8px;\">\r\n                por <span class=\"frequencia-salario-atual\" style=\"font-weight: 500;\"></span> a partir de\r\n            </div>\r\n            <div class=\"form-group\" style=\"float: left; width: 118px; margin-top: -10px;\">\r\n                <input class=\"form-control D data required\" data-val=\"true\" name=\"DataAlteracao\" id=\"DataAlteracao\" type=\"text\" value=\"01/01/0001 00:00:00\" />\r\n                <span id=\"validacao_DataAlteracao\" class=\"tag-campo-obrigatorio\" style=\"display: none\">Campo de preenchimento obrigatório.</span>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n\r\n\r\n\r\n\r\n<div id=\"dialog-nao-optante-parcelamento-fgts-prazo-vigente\" style=\"display: none;\">\r\n    <div class=\"fade-alert alert alert-info\">\r\n        <p></p>\r\n    </div>\r\n</div>\r\n\r\n<div id=\"dialog-nao-optante-parcelamento-fgts-prazo-expirado\" style=\"display: none;\">\r\n    <div class=\"fade-alert alert alert-info\">\r\n        <p></p>\r\n    </div>\r\n</div>\r\n\r\n\r\n    <div id=\"dialog-apoio-financeiro-sul\" style=\"display: none;\">\r\n        <div class=\"fade-alert alert alert-info\">\r\n            <p class=\"text-justify\">O Apoio Financeiro, que é pago diretamente ao empregado, referente a MP 1.230/2024, deve ser informado nas folhas de pagamento de junho e julho de 2024 como desconto do trabalhador que recebeu o benefício através da rubrica eSocial5200 - Apoio Financeiro MP 1230/2024. Para incluir a rubrica, o empregador deve acessar os dados de remuneração do trabalhador e acessar a opção \"Outros Descontos\".</p>\r\n            <p class=\"text-justify\">O valor descontado a título de apoio financeiro será de R$ 1412,00. Caso o valor líquido seja inferior a R$ 1412,00, será lançada a rubrica de vencimento eSocial-1840 para tratamento da insufiência de saldo, valor que poderá ser ressarcido nas folhas de pagamento das competências agosto e setembro de 2024.</p>\r\n        </div>\r\n    </div>\r\n\r\n\r\n\r\n\r\n\r\n        </div>\r\n        <!--Chatbot-->\r\n\r\n        <!--Fim chatbot-->\r\n\r\n    </div>\r\n        <footer id=\"footer\">\r\n            <div class=\"footer-logos\">\r\n                <a href=\"https://www.gov.br/previdencia/pt-br/\" target=\"_blank\">Ministério da <b>Previdência Social</b></a>\r\n                <a href=\"https://www.gov.br/trabalho-e-emprego/pt-br/\" target=\"_blank\">Ministério do <b>Trabalho e Emprego</b></a>\r\n                <a href=\"https://www.gov.br/receitafederal/pt-br/\" target=\"_blank\">Secretaria Especial da <b>Receita Federal do Brasil</b></a>\r\n            </div>\r\n            <div style=\"float: right; margin: 12px 15px;\">eSocial.RecepcaoEvento: 15.9.14 | eSocial.Web.Negocio: 3.15.30</div>\r\n        </footer>\r\n    </div>\r\n    <section id=\"confirma-submit\" onload=\"$('#confirma-submit').hide();\">\r\n        <div class=\"row-fluid\">\r\n            <div class=\"col-md-12 center\">\r\n                <p class=\"mensagem\"></p>\r\n            </div>\r\n        </div>\r\n    </section>\r\n    <div id=\"loading\" class=\"loading\">\r\n        <span>\r\n            <img src=\"/portal/Content/img/ajax-loader.gif\" />\r\n            Carregando...\r\n        </span>\r\n    </div>\r\n    <div id=\"assistente\" class=\"assistente hide\">\r\n        <span>\r\n\r\n            Escutando...\r\n        </span>\r\n    </div>\r\n    <input id=\"HiddenCurrentUrl\" name=\"HiddenCurrentUrl\" type=\"hidden\" value=\"/portal/\" />\r\n    <input id=\"ehCodigoAcesso\" name=\"ehCodigoAcesso\" type=\"hidden\" value=\"False\" />\r\n    <input id=\"hiddenTipoAmbiente\" name=\"hiddenTipoAmbiente\" type=\"hidden\" value=\"1\" />\r\n\r\n    <input id=\"MarcouCheckPopup\" name=\"MarcouCheckPopup\" type=\"hidden\" value=\"\" />;\r\n\r\n\r\n    <input id=\"ProblemaIRRF\" name=\"ProblemaIRRF\" type=\"hidden\" value=\"False\" />;\r\n\r\n    \r\n\r\n<input id=\"EhProcurador\" name=\"EhProcurador\" type=\"hidden\" value=\"True\" /><input id=\"IdentificacaoModulo\" name=\"IdentificacaoModulo\" type=\"hidden\" value=\"Módulo: Geral Pessoa Jurídica\" /><input id=\"TipoAcessoGovBr\" name=\"TipoAcessoGovBr\" type=\"hidden\" value=\"x509\" /><input id=\"TipoAcessoGovBr\" name=\"TipoAcessoGovBr\" type=\"hidden\" value=\"3\" /><input id=\"Origem\" name=\"Origem\" type=\"hidden\" value=\"govbr\" />\r\n\r\n<input data-val=\"true\" data-val-required=\"Campo de preenchimento obrigatório.\" id=\"ExibirTrocarPerfil\" name=\"ExibirTrocarPerfil\" type=\"hidden\" value=\"True\" />\r\n    <div id=\"dialog-sessao-expirou\" style=\"display: none;\">\r\n        <div class=\"fade-alert alert alert-info\">\r\n            <p>Atenção, sua sessão expirou. Clique em continuar para fazer um novo login.</p>\r\n        </div>\r\n    </div>\r\n\r\n    <div id=\"dialog-sessao-quase-expirando\" style=\"display: none;\">\r\n        <div class=\"fade-alert alert alert-info\">\r\n            <p>Atenção, sua sessão irá expirar em {0} minuto(s). Clique em OK para renová-la.</p>\r\n        </div>\r\n    </div>\r\n\r\n    \r\n\r\n    <div id=\"dialog-informe-rendimentos\" style=\"display: none;\">\r\n        <div class=\"alert alert-info alert-info-col\">O Informe de Rendimentos está temporariamente indisponível para ajustes.</div>\r\n    </div>\r\n\r\n\r\n    <div id=\"DivPerguntaValidacao\" class=\"hide\">\r\n        <div class=\"fade-alert alert alert-info margin-left-10px margin-right-10px\" style=\"display: block;\">\r\n            <p class=\"text-justify\"></p>\r\n        </div>\r\n    </div>\r\n\r\n    <div id=\"dialog-valores-ferias-prorrogadas\" style=\"display: none;\">\r\n        \r\n    </div>\r\n\r\n    <!--<div id=\"dialog-alerta-termino-codigo-acesso\" style=\"display: none\">\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            Prezado usuário,\r\n        </div>\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            Você acessou o eSocial utilizando seu código de acesso e senha. O eSocial exige login por meio da conta <a href='https://sso.acesso.gov.br/login' target='_blank'>gov.br</a> níveis ouro ou prata para informar admissões, desligamentos, férias, afastamentos, alterações cadastrais e contratuais.<br />\r\n        </div>\r\n\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            <strong>Em 12/06/2023, o código de acesso será descontinuado em definitivo e você não mais conseguirá acessar o eSocial sem o login via gov.br nível ouro ou prata.</strong><br />\r\n        </div>\r\n\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            Se você ainda não tem, crie sua conta. Se sua conta é nível bronze, aumente para nível ouro ou prata. Para mais informações sobre criação da conta <a href='https://sso.acesso.gov.br/login' target='_blank'>gov.br</a> e como acessar o eSocial por meio dela, ou como aumentar o nível para ouro ou prata, <a href='https://www.gov.br/esocial/pt-br/noticias/fim-do-login-por-codigo-de-acesso-sera-realizado-por-fases' target='_blank'>clique aqui</a>.<br />\r\n        </div>\r\n\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            <label class=\"checkbox-inline\"> Li e estou ciente</label>\r\n            \r\n        </div>\r\n    </div>-->\r\n    <div id=\"dialog-alerta-mensagem-irrf\" style=\"display: none\">\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            <strong>ATENÇÃO:</strong>\r\n        </div>\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            Empregador localizado em município abrangido pelo estado de calamidade pública em decorrência de chuvas intensas no Estado do Rio Grande do Sul.<br />\r\n        </div>\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            Foi identificada a emissão de guia(s) DAE da(s) competência(s) de agosto/2023 e/ou setembro/2023 com encargos e vencimento(s) errados.<br />\r\n        </div>\r\n        <div class=\"row\" style=\"margin-bottom: 20px;\">\r\n            Para evitar o recolhimento da(s) guia(s) com valores incorretos, orientamos o empregador a gerar novamente a(s) guia(s) DAE citada(s).<br />\r\n        </div>\r\n\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    \r\n\r\n    <script src=\"/portal/bundles/jquery?v=G5kkFvMQpux0qFC2o-4OE1xICMwVgutnYpg8nmMqfAs1\"></script>\r\n\r\n    <script src=\"/portal/bundles/json3?v=XXBG0mjti4SegmVL5-5kB0aOhvUJ-aOvl3WjxHEhi241\"></script>\r\n\r\n    <script src=\"/portal/bundles/jqueryui?v=EUUPoa2KN7x0JK6NVoblXEvqR15nyElRCKHrIMkBwhc1\"></script>\r\n\r\n    <script src=\"/portal/bundles/jqueryval?v=Utwo9J8LQ3SPt-uTs_KiXI5S51lw5BgutgQsiic934s1\"></script>\r\n\r\n    <script src=\"/portal/bundles/modernizr?v=wBEWDufH_8Md-Pbioxomt90vm6tJN2Pyy9u9zHtWsPo1\"></script>\r\n\r\n    <script src=\"/portal/bundles/currency?v=UTcTuQi2R900YMnNIC0RkDzotP459uLF278AZbN213c1\"></script>\r\n\r\n    <script src=\"/portal/bundles/bootstrap?v=9q_KeIQFH5jkegRoAOf_JsVT1jhQsXPn-F4iv2f_nzM1\"></script>\r\n\r\n    <script src=\"/portal/bundles/comum?v=FmWR6jUYeJvueYOoWmHXeTNixPBRAyArEj0oTapMP201\"></script>\r\n\r\n    <script src=\"/portal/bundles/mobile?v=Rr3XP4F9PSIypqG2J-zrVRsJ2YHf6RkypRCqd_0uZ7Y1\"></script>\r\n\r\n    <script src=\"/portal/bundles/chatbot?v=diHBYO9lrQEWY9mDbFfkDtVbf3-jn3qNWQVC-pMdq_U1\"></script>\r\n\r\n\r\n    \r\n    <script src=\"/portal/bundles/home?v=kbxevD2i-XIZ1Wn80vvrGTTC4sf0AbJkp1MGp641xj01\"></script>\r\n\r\n    <script src=\"/portal/bundles/formularioComum?v=Zuj9mV9HZX38uWEchD5P1QZOLxr2wwbUkVDdzqkylsQ1\"></script>\r\n\r\n    <script src=\"/portal/bundles/AcessoRapido?v=x_PE-9s_13fppv7h6tu8j2HtwHlqju73YIiLeVy0IOc1\"></script>\r\n\r\n\r\n\r\n\r\n    \r\n\r\n    <!-- Inclusão de script para coleta de scripts (somente produção) -->\r\n    \r\n</body>\r\n</html>\r\n<!--\r\n    Versão: \r\n-->\r\n"
